var http = require('http');
var express = require('express');
var { RtcTokenBuilder, RtmTokenBuilder, RtcRole, RtmRole } = require('agora-access-token');

var PORT = 8081;

var appID = "a93ba219be3f40749b249260dea5b140";
var appCertificate = "8f794cc1f99b4ab6a4d77b50c46f6f74";

var expirationTimeInSeconds = 3600;
var role = RtcRole.PUBLISHER;

var app = express();
app.disable('x-powered-by');

// REMOVE THESE (they crash on new Express)
// app.use(express.favicon());
// app.use(app.router);

// Just use routes directly
app.set('port', PORT);

var generateRtcToken = function(req, resp) {
    var currentTimestamp = Math.floor(Date.now() / 1000);
    var privilegeExpiredTs = currentTimestamp + expirationTimeInSeconds;

    var channelName = req.query.channelName;
    var uid = req.query.uid || 0;

    if (!channelName) {
        return resp.status(400).json({ error: 'channel name is required' });
    }

    var key = RtcTokenBuilder.buildTokenWithUid(
        appID,
        appCertificate,
        channelName,
        uid,
        role,
        privilegeExpiredTs
    );

    resp.setHeader("Access-Control-Allow-Origin", "*");
    return resp.json({ key: key });
};

var generateRtmToken = function(req, resp) {
    var currentTimestamp = Math.floor(Date.now() / 1000);
    var privilegeExpiredTs = currentTimestamp + expirationTimeInSeconds;

    var account = req.query.account;
    if (!account) {
        return resp.status(400).json({ error: 'account is required' });
    }

    var key = RtmTokenBuilder.buildToken(
        appID,
        appCertificate,
        account,
        RtmRole,
        privilegeExpiredTs
    );

    resp.setHeader("Access-Control-Allow-Origin", "*");
    return resp.json({ key: key });
};

app.get('/rtcToken', generateRtcToken);
app.get('/rtmToken', generateRtmToken);

http.createServer(app).listen(app.get('port'), function() {
    console.log('AgoraSignServer starts at ' + app.get('port'));
});
